/**
 * Builds a minimal fetch `Response` stand-in for the mocked global `fetch`.
 *
 * `text()` returns the raw text (defaults to the JSON-stringified body).
 * `json()` returns the parsed body when one is provided; otherwise it falls
 * back to parsing `text` as JSON (when only `text` was given), and finally to
 * an empty object. `ok` is derived from `status` (true for any 2xx) unless an
 * explicit `ok` is supplied, in which case it wins.
 *
 * The `json()` method prefers an explicit `body` when supplied. When only
 * `text` was given, it parses the text as JSON; when neither is supplied it
 * falls back to an empty object `{}`. (No call site actually relies on this
 * branch: on the error path `ApiClient.request` only reads `.text()`, and on
 * the success path a `body` is always supplied.) The behavior is pinned by the
 * `mockResponse helper` characterization suite in `src/api.test.ts`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/test-utils/**` glob in `tsconfig.json`'s `exclude` array, so it is
 * never shipped to `wwwroot/dist`. Only test files import it.
 */
export interface MockResponseOptions {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}

export function mockResponse(opts: MockResponseOptions): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => opts.body ?? (opts.text ? JSON.parse(opts.text) : {}),
  } as unknown as Response;
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ApiClient, type FileEntry, type BrowseResult, type SearchResult } from './api';
import { mockResponse } from './test-utils/mock-response';

describe('ApiClient', () => {
  let fetchMock: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    fetchMock = vi.fn();
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('defaults baseUrl to /api/files', () => {
      const client = new ApiClient();
      expect(client.downloadUrl('x')).toBe('/api/files/download?path=x');
    });

    it('honors a custom baseUrl', () => {
      const client = new ApiClient('/custom/api');
      expect(client.downloadUrl('x')).toBe('/custom/api/download?path=x');
    });
  });

  describe('browse', () => {
    it('GETs the browse endpoint with an encoded path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const entries: FileEntry[] = [
        {
          name: 'a.txt',
          path: '/root/a.txt',
          isDirectory: false,
          size: 10,
          lastModified: '2024-01-01T00:00:00Z',
        },
      ];
      const result: BrowseResult = {
        path: '/root',
        parent: '/',
        entries,
        folderCount: 0,
        fileCount: 1,
        totalSize: 10,
      };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: result }));

      const data = await client.browse('/root');

      expect(fetchMock).toHaveBeenCalledTimes(1);
      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('GET');
      expect(data).toEqual(result);
    });

    it('encodes special characters in the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({
          body: { path: '', parent: null, entries: [], folderCount: 0, fileCount: 0, totalSize: 0 },
        }),
      );
      const tricky = '/foo bar/baz?x=1&y=2';
      await client.browse(tricky);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent(tricky));
    });

    it('throws an Error containing status and response text on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 404, text: 'Not Found' }));

      await expect(client.browse('/missing')).rejects.toThrow('404: Not Found');
      await expect(client.browse('/missing')).rejects.toBeInstanceOf(Error);
    });

    it('throws a plain Error instance (not a string) on failure', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValue(mockResponse({ status: 500, text: 'boom' }));
      await expect(client.browse('/x')).rejects.toBeInstanceOf(Error);
    });
  });

  describe('search', () => {
    it('GETs the search endpoint with encoded query and path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const results: FileEntry[] = [
        {
          name: 'match.txt',
          path: '/root/match.txt',
          isDirectory: false,
          size: 5,
          lastModified: '2024-02-02T00:00:00Z',
        },
      ];
      const out: SearchResult = { query: 'mat', path: '/root', results };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: out }));

      const data = await client.search('mat', '/root');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe(
        '/api/files/search?query=' +
          encodeURIComponent('mat') +
          '&path=' +
          encodeURIComponent('/root'),
      );
      expect(init?.method).toBe('GET');
      expect(data).toEqual(out);
    });

    it('encodes special characters in both query and path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { query: '', path: '', results: [] } }));
      const q = 'a b&c';
      const p = '/dir x/y?z=1';
      await client.search(q, p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe(
        '/api/files/search?query=' + encodeURIComponent(q) + '&path=' + encodeURIComponent(p),
      );
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 400, text: 'Bad Request' }));
      await expect(client.search('q', '/p')).rejects.toThrow('400: Bad Request');
    });
  });

  describe('upload', () => {
    it('POSTs multipart form data with a file field named "file" and returns parsed JSON', async () => {
      const client = new ApiClient();
      const file = new File(['hello'], 'hello.txt', { type: 'text/plain' });
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '/root/hello.txt' } }));

      const data = await client.upload('/root', file);

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('POST');
      const body = init?.body;
      expect(body).toBeInstanceOf(FormData);
      expect((body as FormData).get('file')).toBe(file);
      expect(data).toEqual({ path: '/root/hello.txt' });
    });

    it('encodes the destination path in the query string', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '' } }));
      const dest = '/some dir/sub?x=1';
      await client.upload(dest, file);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent(dest));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 413, text: 'Too Large' }));
      await expect(client.upload('/root', file)).rejects.toThrow('413: Too Large');
    });
  });

  describe('delete', () => {
    it('issues a DELETE to the delete endpoint and resolves to void on success', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204, body: null }));

      const result = await client.delete('/root/old.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent('/root/old.txt'));
      expect(init?.method).toBe('DELETE');
      expect(result).toBeUndefined();
    });

    it('encodes the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204 }));
      const p = '/a b/c?d=1';
      await client.delete(p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 403, text: 'Forbidden' }));
      await expect(client.delete('/nope')).rejects.toThrow('403: Forbidden');
    });
  });

  describe('move', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.move('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/move');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({
        sourcePath: '/a/b.txt',
        destinationPath: '/c/b.txt',
      });
      expect(result).toBeUndefined();
    });

    it('does not encode paths because they ride in a JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.move('/a b/c?x=1', '/d e/f?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/a b/c?x=1', destinationPath: '/d e/f?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 409, text: 'Conflict' }));
      await expect(client.move('/a', '/b')).rejects.toThrow('409: Conflict');
    });
  });

  describe('copy', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.copy('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/copy');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({
        sourcePath: '/a/b.txt',
        destinationPath: '/c/b.txt',
      });
      expect(result).toBeUndefined();
    });

    it('sends the raw paths in the JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.copy('/src dir/f?x=1', '/dst dir/g?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/src dir/f?x=1', destinationPath: '/dst dir/g?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 500, text: 'Server Error' }));
      await expect(client.copy('/a', '/b')).rejects.toThrow('500: Server Error');
    });
  });

  describe('createDirectory', () => {
    it('POSTs to the mkdir endpoint with an encoded path and resolves void on success', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: { success: true } }));

      const result = await client.createDirectory('docs/new folder');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/mkdir?path=' + encodeURIComponent('docs/new folder'));
      expect(init?.method).toBe('POST');
      // No request body — the path rides in the query string.
      expect(init?.body).toBeUndefined();
      expect(result).toBeUndefined();
    });

    it('encodes the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      const p = 'a b/c?d=1';
      await client.createDirectory(p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/mkdir?path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 400, text: 'Bad Request' }));
      await expect(client.createDirectory('../escape')).rejects.toThrow('400: Bad Request');
    });
  });

  describe('downloadUrl', () => {
    it('returns the encoded download URL synchronously without calling fetch', () => {
      const client = new ApiClient();
      const url = client.downloadUrl('/root/file.txt');
      expect(url).toBe('/api/files/download?path=' + encodeURIComponent('/root/file.txt'));
      expect(fetchMock).not.toHaveBeenCalled();
    });

    it('encodes special characters', () => {
      const client = new ApiClient();
      const tricky = '/a b/c?d=1&e=2';
      expect(client.downloadUrl(tricky)).toBe(
        '/api/files/download?path=' + encodeURIComponent(tricky),
      );
    });

    it('respects a custom baseUrl', () => {
      const client = new ApiClient('/api/v2/files');
      expect(client.downloadUrl('x')).toBe('/api/v2/files/download?path=x');
    });
  });
});

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts'],
  },
});

import { describe, it, expect } from 'vitest';
import { mockResponse } from './mock-response';

/* ===========================================================================
 * Characterization suite for the `mockResponse` test helper.
 *
 * `mockResponse` builds a minimal fetch `Response` stand-in consumed by every
 * ApiClient / app test. Its fallback behavior (how `ok`, `text()`, and `json()`
 * are derived) was previously described only in a doc comment — and that
 * comment referenced a characterization suite that no longer existed, leaving
 * the helper's observable behavior unverified. These tests pin the documented
 * contract directly so that a change to any fallback is caught here, regardless
 * of which higher-level test happens to exercise it.
 *
 * Implementation under test (for reference):
 *   const status = opts.status ?? 200;
 *   const ok     = opts.ok ?? (status >= 200 && status < 300);
 *   const text   = opts.text ?? JSON.stringify(opts.body ?? {});
 *   json: async () => opts.body ?? (opts.text ? JSON.parse(opts.text) : {}),
 * ========================================================================= */

describe('mockResponse — status', () => {
  it('defaults status to 200 when omitted', () => {
    expect(mockResponse({}).status).toBe(200);
  });

  it('honors an explicit status code', () => {
    expect(mockResponse({ status: 404 }).status).toBe(404);
    expect(mockResponse({ status: 503 }).status).toBe(503);
  });

  it('passes the status through verbatim (no coercion of the supplied value)', () => {
    expect(mockResponse({ status: 204 }).status).toBe(204);
  });
});

describe('mockResponse — ok is derived from status for 2xx ranges', () => {
  it('is true for the default 200', () => {
    expect(mockResponse({}).ok).toBe(true);
  });

  it('is true at the inclusive 2xx boundaries (200 and 299)', () => {
    expect(mockResponse({ status: 200 }).ok).toBe(true);
    expect(mockResponse({ status: 299 }).ok).toBe(true);
  });

  it('is true for mid-range 2xx values (204, 226, 250)', () => {
    // Pins the WHOLE range, not just the endpoints — guards against an off-by-one
    // like `status > 200 && status < 299`.
    expect(mockResponse({ status: 204 }).ok).toBe(true);
    expect(mockResponse({ status: 226 }).ok).toBe(true);
    expect(mockResponse({ status: 250 }).ok).toBe(true);
  });

  it('is false just below the 2xx range (199)', () => {
    expect(mockResponse({ status: 199 }).ok).toBe(false);
  });

  it('is false just above the 2xx range (300)', () => {
    expect(mockResponse({ status: 300 }).ok).toBe(false);
  });

  it('is false for 1xx informational statuses (100, 101)', () => {
    // Pins that the 2xx range is exclusive of 1xx, not `status >= 100`.
    expect(mockResponse({ status: 100 }).ok).toBe(false);
    expect(mockResponse({ status: 101 }).ok).toBe(false);
  });

  it('is false for 3xx redirection statuses (301, 304)', () => {
    // A redirect (3xx) is NOT ok by this helper's contract.
    expect(mockResponse({ status: 301 }).ok).toBe(false);
    expect(mockResponse({ status: 304 }).ok).toBe(false);
  });

  it('is false for common error statuses (404, 500, 503)', () => {
    expect(mockResponse({ status: 404 }).ok).toBe(false);
    expect(mockResponse({ status: 500 }).ok).toBe(false);
    expect(mockResponse({ status: 503 }).ok).toBe(false);
  });

  it('returns status as a number (no string coercion)', () => {
    expect(typeof mockResponse({}).status).toBe('number');
    expect(typeof mockResponse({ status: 404 }).status).toBe('number');
  });
});

describe('mockResponse — explicit ok overrides the status-derived value', () => {
  it('forces ok true even for a non-2xx status', () => {
    // `ok` is supplied, so it wins over the status range.
    expect(mockResponse({ ok: true, status: 500 }).ok).toBe(true);
  });

  it('forces ok false even for a 2xx status', () => {
    // Toolbar-handler tests rely on this: `mockResponse({ ok: false, status: 413 })`.
    expect(mockResponse({ ok: false, status: 200 }).ok).toBe(false);
    expect(mockResponse({ ok: false, status: 413 }).ok).toBe(false);
  });

  it('explicit ok:false beats status-derived true even when status is omitted', () => {
    // status defaults to 200 (would derive ok=true), but the explicit flag wins.
    expect(mockResponse({ ok: false }).ok).toBe(false);
  });
});

describe('mockResponse — text()', () => {
  it('returns the raw `text` option verbatim when supplied', async () => {
    const res = mockResponse({ text: 'Not Found' });
    expect(await res.text()).toBe('Not Found');
  });

  it('returns JSON-stringified `body` when `text` is omitted', async () => {
    const res = mockResponse({ body: { a: 1, b: [2, 3] } });
    expect(await res.text()).toBe(JSON.stringify({ a: 1, b: [2, 3] }));
  });

  it('defaults to "{}" when neither `text` nor `body` is supplied', async () => {
    // text = opts.text ?? JSON.stringify(opts.body ?? {})  =>  JSON.stringify({})  => '{}'
    expect(await mockResponse({}).text()).toBe('{}');
  });

  it('stringifies a falsy-but-defined body (e.g. 0, false, "") rather than "{}"', async () => {
    // `opts.body ?? {}` uses nullish-coalescing, so 0/false/'' survive.
    expect(await mockResponse({ body: 0 }).text()).toBe('0');
    expect(await mockResponse({ body: false }).text()).toBe('false');
    expect(await mockResponse({ body: '' }).text()).toBe('""');
  });

  it('is async (returns a Promise that resolves to a string)', async () => {
    const res = mockResponse({ text: 'hello' });
    expect(typeof res.text).toBe('function');
    const result = res.text();
    expect(result).toBeInstanceOf(Promise);
    expect(await result).toBe('hello');
  });

  it('returns the same text on repeated calls (no one-shot semantics)', async () => {
    const res = mockResponse({ body: { n: 1 } });
    expect(await res.text()).toBe('{"n":1}');
    expect(await res.text()).toBe('{"n":1}');
  });

  it('serializes a null body to "{}" just like an omitted body', async () => {
    // `opts.body ?? {}` treats null as nullish, so null and undefined behave the
    // same for text(): both yield JSON.stringify({}) === '{}'.
    expect(await mockResponse({ body: null }).text()).toBe('{}');
    expect(await mockResponse({ body: undefined }).text()).toBe('{}');
    expect(await mockResponse({}).text()).toBe('{}');
  });
});

describe('mockResponse — json() prefers an explicit body', () => {
  it('returns the body object as-is', async () => {
    const body = { path: '/x', entries: [] };
    expect(await mockResponse({ body }).json()).toEqual(body);
  });

  it('returns the body verbatim, not JSON.parse(JSON.stringify(body))', async () => {
    // Same reference identity must be preserved (no clone / re-parse round trip).
    const body = { a: 1, nested: { b: 2 } };
    expect(await mockResponse({ body }).json()).toBe(body);
  });

  it('returns arrays, numbers, and booleans unchanged', async () => {
    expect(await mockResponse({ body: [1, 2, 3] }).json()).toEqual([1, 2, 3]);
    expect(await mockResponse({ body: 42 }).json()).toBe(42);
    expect(await mockResponse({ body: true }).json()).toBe(true);
  });

  it('body wins over `text` when both are supplied', async () => {
    // json = opts.body ?? (...) — body short-circuits before `text` is parsed.
    const res = mockResponse({ body: { ok: true }, text: '{"ok":false}' });
    expect(await res.json()).toEqual({ ok: true });
    // `text()` still returns the raw text option untouched.
    expect(await res.text()).toBe('{"ok":false}');
  });
});

describe('mockResponse — json() nullish-body edge cases (?? semantics)', () => {
  it('treats an explicit null body as nullish and falls through to the text branch', async () => {
    // opts.body ?? (...) — `null` is nullish, so json() does NOT return null.
    // With no `text`, it falls all the way back to {}.
    expect(await mockResponse({ body: null }).json()).toEqual({});
  });

  it('parses `text` as JSON when body is null', async () => {
    expect(await mockResponse({ body: null, text: '{"x":42}' }).json()).toEqual({ x: 42 });
  });

  it('returns a falsy-but-defined body (0, false, "") unchanged', async () => {
    // Distinct from null/undefined: ?? only treats null/undefined as nullish.
    expect(await mockResponse({ body: 0 }).json()).toBe(0);
    expect(await mockResponse({ body: false }).json()).toBe(false);
    expect(await mockResponse({ body: '' }).json()).toBe('');
  });
});

describe('mockResponse — json() parses `text` when only text is given', () => {
  it('parses the raw text as JSON', async () => {
    const res = mockResponse({ text: '{"path":"/missing"}' });
    expect(await res.json()).toEqual({ path: '/missing' });
  });

  it('parses non-object JSON payloads (arrays, numbers)', async () => {
    expect(await mockResponse({ text: '[1,2,3]' }).json()).toEqual([1, 2, 3]);
    expect(await mockResponse({ text: '7' }).json()).toBe(7);
  });

  it('throws a SyntaxError when `text` is not valid JSON', async () => {
    // This is the error path ApiClient relies on: it reads .text(), never .json(),
    // on failures — but json() itself must surface invalid JSON rather than hide it.
    await expect(mockResponse({ text: 'Not Found' }).json()).rejects.toThrow(SyntaxError);
  });

  it('falls back to {} for an empty-string `text` ("" is falsy, not nullish)', async () => {
    // SUBTLE: json() uses a TRUTHINESS check (`opts.text ? ...`), not nullish.
    // So '' is treated as "no text" and json() returns {} rather than throwing
    // a SyntaxError on JSON.parse(''). Pins this exact interaction so a refactor
    // to `opts.text != null` would be caught.
    const res = mockResponse({ text: '' });
    expect(await res.json()).toEqual({});
    // text() still returns the empty string verbatim.
    expect(await res.text()).toBe('');
  });
});

describe('mockResponse — json() empty fallback', () => {
  it('returns {} when neither body nor text is supplied', async () => {
    // json = opts.body ?? (opts.text ? JSON.parse(opts.text) : {})  =>  {}
    expect(await mockResponse({}).json()).toEqual({});
  });

  it('returns {} when body and text are both explicitly undefined', async () => {
    expect(await mockResponse({ body: undefined, text: undefined }).json()).toEqual({});
  });

  it('is async (returns a Promise)', async () => {
    const res = mockResponse({});
    expect(typeof res.json).toBe('function');
    expect(res.json()).toBeInstanceOf(Promise);
  });
});

describe('mockResponse — returned object shape', () => {
  it('exposes ok, status, and async text()/json() methods', async () => {
    const res = mockResponse({ status: 200, body: { a: 1 } });
    expect(res).toHaveProperty('ok', true);
    expect(res).toHaveProperty('status', 200);
    expect(typeof res.text).toBe('function');
    expect(typeof res.json).toBe('function');
    expect(await res.json()).toEqual({ a: 1 });
  });

  it('reflects the same status on the returned object regardless of ok override', async () => {
    // `ok` and `status` are independent: overriding ok must not mutate status.
    const res = mockResponse({ ok: false, status: 413, text: 'too large' });
    expect(res.status).toBe(413);
    expect(res.ok).toBe(false);
    expect(await res.text()).toBe('too large');
  });
});

import { describe, it, expect } from 'vitest';
import * as formatModule from './format';
import { formatBytes, normalizeRelativePath, joinPath, formatDate } from './format';

/* ===========================================================================
 * Module surface
 *
 * `src/format.ts` exports ONLY these four functions and nothing else. This
 * guard test pins that contract so a stray export does not sneak in — and so
 * the removal of the dead `parentPath` / `basename` exports (which production
 * code never imported) cannot be silently re-added. Production consumes exactly
 * this set: formatBytes, formatDate, joinPath, normalizeRelativePath.
 * ========================================================================= */
describe('format module surface', () => {
  it('exports exactly the four documented functions', () => {
    expect(Object.keys(formatModule).sort()).toEqual([
      'formatBytes',
      'formatDate',
      'joinPath',
      'normalizeRelativePath',
    ]);
  });
});

/* ===========================================================================
 * formatBytes
 *
 * Binary (1024-based) units: B, KB, MB, GB, TB.
 *  - bytes < 1024 render as an integer byte count (e.g. "1023 B").
 *  - bytes >= 1024 render with exactly one decimal place (e.g. "1.5 KB").
 * ========================================================================= */
describe('formatBytes', () => {
  it('formats zero bytes', () => {
    expect(formatBytes(0)).toBe('0 B');
  });

  it('formats a single byte', () => {
    expect(formatBytes(1)).toBe('1 B');
  });

  it('renders values under 1024 as an integer byte count with no decimals', () => {
    expect(formatBytes(1023)).toBe('1023 B');
    expect(formatBytes(512)).toBe('512 B');
  });

  it('renders exactly one kilobyte keeping the ".0" decimal', () => {
    // Spec: 1 decimal when >= 1024, so the trailing .0 is preserved.
    expect(formatBytes(1024)).toBe('1.0 KB');
  });

  it('formats 1536 bytes as 1.5 KB (the documented example)', () => {
    expect(formatBytes(1536)).toBe('1.5 KB');
  });

  it('rounds to one decimal place (2000 -> 2.0 KB)', () => {
    // 2000 / 1024 = 1.953125 -> one decimal rounds up to 2.0
    expect(formatBytes(2000)).toBe('2.0 KB');
  });

  it('formats exactly one megabyte keeping the ".0" decimal (documented example)', () => {
    expect(formatBytes(1048576)).toBe('1.0 MB');
  });

  it('formats 1.5 megabytes', () => {
    expect(formatBytes(1572864)).toBe('1.5 MB'); // 1.5 * 1024 * 1024
  });

  it('formats exactly one gigabyte', () => {
    expect(formatBytes(1073741824)).toBe('1.0 GB'); // 1024 ** 3
  });

  it('formats exactly one terabyte', () => {
    expect(formatBytes(1099511627776)).toBe('1.0 TB'); // 1024 ** 4
  });

  it('does not exceed the TB unit for very large values', () => {
    // 1024 ** 5 would be PB, but the documented unit set stops at TB.
    expect(formatBytes(1099511627776 * 2)).toBe('2.0 TB');
  });
});

/* ===========================================================================
 * normalizeRelativePath
 *
 *  - replace backslashes with '/'
 *  - trim leading/trailing '/'
 *  - collapse repeated '/'
 *  - drop '.' segments and '..' segments (filtered out, NOT resolved)
 *  - return '' for root/empty
 * ========================================================================= */
describe('normalizeRelativePath', () => {
  it('returns empty string for empty input', () => {
    expect(normalizeRelativePath('')).toBe('');
  });

  it('returns empty string for root', () => {
    expect(normalizeRelativePath('/')).toBe('');
  });

  it('returns empty string for a lone backslash (windows root)', () => {
    expect(normalizeRelativePath('\\')).toBe('');
  });

  it('returns empty string for an all-root input', () => {
    expect(normalizeRelativePath('///')).toBe('');
  });

  it('keeps a single clean segment unchanged', () => {
    expect(normalizeRelativePath('foo')).toBe('foo');
  });

  it('keeps multiple clean segments unchanged', () => {
    expect(normalizeRelativePath('foo/bar/baz')).toBe('foo/bar/baz');
  });

  it('trims a leading slash', () => {
    expect(normalizeRelativePath('/foo')).toBe('foo');
  });

  it('trims a trailing slash', () => {
    expect(normalizeRelativePath('foo/')).toBe('foo');
  });

  it('trims both leading and trailing slashes', () => {
    expect(normalizeRelativePath('/foo/bar/')).toBe('foo/bar');
  });

  it('collapses repeated slashes', () => {
    expect(normalizeRelativePath('foo//bar')).toBe('foo/bar');
    expect(normalizeRelativePath('//foo//bar//')).toBe('foo/bar');
  });

  it('replaces backslashes with forward slashes', () => {
    expect(normalizeRelativePath('foo\\bar')).toBe('foo/bar');
    expect(normalizeRelativePath('foo\\bar\\baz')).toBe('foo/bar/baz');
  });

  it('drops a single "." segment', () => {
    expect(normalizeRelativePath('foo/./bar')).toBe('foo/bar');
  });

  it('drops a trailing "." segment', () => {
    expect(normalizeRelativePath('foo/bar/.')).toBe('foo/bar');
  });

  it('drops a leading "." segment', () => {
    expect(normalizeRelativePath('./foo')).toBe('foo');
  });

  it('returns empty string for a lone "." or ".."', () => {
    expect(normalizeRelativePath('.')).toBe('');
    expect(normalizeRelativePath('..')).toBe('');
  });

  it('drops ".." segments rather than resolving them against the parent', () => {
    // Spec wording: "drop '.' segments and '..' segments". A ".." token is
    // filtered out of the segment list; it does NOT pop the previous segment.
    expect(normalizeRelativePath('foo/../bar')).toBe('foo/bar');
    expect(normalizeRelativePath('../foo')).toBe('foo');
  });

  it('drops mixed "." and ".." segments together with repeated slashes', () => {
    expect(normalizeRelativePath('a/../..//b')).toBe('a/b');
  });

  it('returns empty string when every segment is dropped', () => {
    expect(normalizeRelativePath('/./../')).toBe('');
  });

  it('drops multi-level "../../.." sequences entirely (still no resolution)', () => {
    // Reviewer suggestion: multi-level dotdots. Per the "drop" semantics all
    // of these are filtered out, leaving nothing.
    expect(normalizeRelativePath('../../..')).toBe('');
    expect(normalizeRelativePath('../../../')).toBe('');
  });

  it('drops interleaved multi-level dotdots while keeping real segments', () => {
    // segments: [a, .., .., b, ..] -> filter dots -> [a, b]
    expect(normalizeRelativePath('a/../../b/..')).toBe('a/b');
  });

  it('preserves dots WITHIN segment names (only exact "." / ".." are dropped)', () => {
    // A segment is dropped only when it is exactly "." or "..". Dots inside a
    // real segment (file extensions, dotfiles, names like "..hidden") must be
    // kept verbatim — a regression that filtered any segment *containing* a dot
    // would silently mangle every filename in the browser. This pins the
    // filter's exact-match semantics on behalf of the KEPT function.
    expect(normalizeRelativePath('file.tar.gz')).toBe('file.tar.gz');
    expect(normalizeRelativePath('a/b.txt/c.d')).toBe('a/b.txt/c.d');
    expect(normalizeRelativePath('.gitignore')).toBe('.gitignore');
    expect(normalizeRelativePath('docs/.gitignore')).toBe('docs/.gitignore');
    // "..hidden" and "..." are not exactly "..", so they survive.
    expect(normalizeRelativePath('..hidden')).toBe('..hidden');
    expect(normalizeRelativePath('a/.../b')).toBe('a/.../b');
  });
});

/* ===========================================================================
 * joinPath
 *
 * join with a single '/' then run the result through normalizeRelativePath.
 * ========================================================================= */
describe('joinPath', () => {
  it('joins two simple segments', () => {
    expect(joinPath('foo', 'bar')).toBe('foo/bar');
  });

  it('normalizes a trailing slash on the base', () => {
    expect(joinPath('foo/', 'bar')).toBe('foo/bar');
  });

  it('normalizes a leading slash on the name', () => {
    expect(joinPath('foo', '/bar')).toBe('foo/bar');
  });

  it('normalizes slashes on both sides', () => {
    expect(joinPath('foo/', '/bar')).toBe('foo/bar');
  });

  it('returns just the name when the base is empty', () => {
    expect(joinPath('', 'bar')).toBe('bar');
  });

  it('returns just the base when the name is empty', () => {
    // base + '/' + '' -> 'foo/' -> normalize -> 'foo'
    expect(joinPath('foo', '')).toBe('foo');
  });

  it('returns empty string when both parts are empty', () => {
    expect(joinPath('', '')).toBe('');
  });

  it('joins multi-segment paths', () => {
    expect(joinPath('a/b', 'c/d')).toBe('a/b/c/d');
  });

  it('normalizes backslashes in the joined result', () => {
    expect(joinPath('foo\\', 'bar')).toBe('foo/bar');
  });

  it('preserves dots in the joined name (filenames, extensions, dotfiles)', () => {
    // joinPath delegates to normalizeRelativePath, so a name carrying dots
    // (a real filename, an extension, a dotfile) must round-trip unchanged.
    // joinPath builds new-directory paths and breadcrumb cumulative paths
    // in production.
    expect(joinPath('docs', 'report.final.txt')).toBe('docs/report.final.txt');
    expect(joinPath('docs', '.gitignore')).toBe('docs/.gitignore');
    expect(joinPath('a/b', 'c.archive.tar.gz')).toBe('a/b/c.archive.tar.gz');
  });
});

/* ===========================================================================
 * formatDate
 *
 * Parse an ISO date string; return '' for empty/invalid; otherwise render as
 * 'yyyy-MM-dd HH:mm' (local calendar time). The offset-free ISO datetimes used
 * below are parsed as local time, so the expected output is stable regardless
 * of the host time zone for a manual local-getter formatter.
 * ========================================================================= */
describe('formatDate', () => {
  it('returns empty string for an empty input', () => {
    expect(formatDate('')).toBe('');
  });

  it('returns empty string for a non-date string', () => {
    expect(formatDate('not-a-date')).toBe('');
  });

  it('returns empty string for arbitrary garbage', () => {
    expect(formatDate('abc')).toBe('');
  });

  it('does not throw for invalid input', () => {
    expect(() => formatDate('nope')).not.toThrow();
  });

  it('formats a local datetime as yyyy-MM-dd HH:mm', () => {
    expect(formatDate('2023-06-15T09:05:00')).toBe('2023-06-15 09:05');
  });

  it('formats an evening datetime', () => {
    expect(formatDate('2024-02-29T23:59:00')).toBe('2024-02-29 23:59');
  });

  it('pads single-digit month, day, hour and minute with a leading zero', () => {
    expect(formatDate('2023-01-05T08:02:00')).toBe('2023-01-05 08:02');
  });

  it('drops seconds (only year-month-day hour:minute are rendered)', () => {
    expect(formatDate('2023-06-15T09:05:45')).toBe('2023-06-15 09:05');
  });

  it('accepts a UTC "Z" offset and renders the yyyy-MM-dd HH:mm shape', () => {
    // Reviewer suggestion: timezone offsets. A trailing 'Z' makes the input
    // UTC, so the exact local output depends on the host time zone. We
    // therefore assert the format/shape rather than a literal value, and
    // that a valid offset-bearing date is NOT treated as invalid (i.e. the
    // result is a non-empty, properly-shaped string).
    const result = formatDate('2023-06-15T09:05:00Z');
    expect(result).not.toBe('');
    expect(result).toMatch(/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/);
  });

  it('accepts a numeric "+HH:MM" offset and renders the yyyy-MM-dd HH:mm shape', () => {
    const result = formatDate('2023-06-15T09:05:00+05:30');
    expect(result).not.toBe('');
    expect(result).toMatch(/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/);
  });
});

